import React, { createContext, useContext, useState, useCallback } from 'react';
import { login as apiLogin, signup as apiSignup } from '../api';
import toast from 'react-hot-toast';
const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(() => {
    try {
      const u = localStorage.getItem('user');
      return u ? JSON.parse(u) : null;
    } catch {
      return null;
    }
  });

  const [token, setToken] = useState(() => localStorage.getItem('token') || null);

  const login = useCallback(async (email, password) => {
    const res = await apiLogin({ email, password });
    const { token: t } = res.data;
    // Decode payload to get user info (role, id, name from JWT)
    const payload = JSON.parse(atob(t.split('.')[1]));
    // Backend returns { token } from login — user info is in JWT payload
    // We also need name/email so we combine payload with request data
    const userData = {
      _id: payload.id,
      role: payload.role,
      email,
    };
    localStorage.setItem('token', t);
    localStorage.setItem('user', JSON.stringify(userData));
    setToken(t);
    setUser(userData);
    return userData;
  }, []);

  const signupUser = useCallback(async ({ name, email, password, role }) => {
  try {
    // 1. Signup only
    await apiSignup({ name, email, password, role });

    // 2. Login immediately
    const loginRes = await apiLogin({ email, password });

    const { token } = loginRes.data;

    // 3. Save token
    localStorage.setItem('token', token);

    // 4. Decode token (optional)
    const payload = JSON.parse(atob(token.split('.')[1]));

    const userData = {
      _id: payload.id,
      role: payload.role,
      email
    };

    localStorage.setItem('user', JSON.stringify(userData));

    setToken(token);
    setUser(userData);

    return userData;

  } catch (err) {
  console.log(err.response?.data);
  toast.error(err.response?.data?.msg || err.response?.data?.error || 'Signup failed');
}
}, []);
  const logout = useCallback(() => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setToken(null);
    setUser(null);
  }, []);

  const isAdmin = user?.role === 'Admin';

  return (
    <AuthContext.Provider value={{ user, token, isAdmin, login, signup: signupUser, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};
